registerTag({
  tag: 'attachments',
  kind: 'module',
  parent: 'cella',
  description: `Endpoints for managing file based *attachments* (e.g. images, PDFs, documents) linked to
    entities such as organizations or users. Files are uploaded directly by the client; the API handles
    metadata registration, linking, access, and preview utilities.`,
});

registerTag({
  tag: 'entities',
  kind: 'module',
  parent: 'cella',
  description: `Endpoints that operate across multiple *entity types*, such as \`users\` and \`organizations\`.
    *Entities* are identifiable domain objects that may be contextual, hierarchical (with parent/child
    relations), or actor-like. These endpoints offer shared logic across modules, including slug validation
    and entity visibility.`,
});

registerTag({
  tag: 'me',
  kind: 'module',
  parent: 'cella',
  description: `Endpoints related to the *current user*, meaning the user associated with the active session making
    the request. These routes are distinct from general \`users\` endpoints: while \`users\` may operate on
    any user in the system, \`me\` endpoints are scoped exclusively to the *current user* and follow a
    different authorization flow.`,
});

registerTag({
  tag: 'memberships',
  kind: 'module',
  parent: 'cella',
  description: `Endpoints for managing *memberships*, which represent one-to-one relationships between a
    \`user\` and a contextual \`entity\` (e.g., an \`organization\`). Each membership includes role information
    and status flags such as \`archived\` or \`muted\`. Memberships can also reference parent entities,
    enabling hierarchical context.`,
});

const findMembershipByIdInOrg = async (ctx: AuthContext, { membershipId }: FindMembershipByIdInOrgOpts) => {
  const { db, organizationId } = ctx.var;
  const [membership] = await db
    .select(membershipBaseSelect)
    .from(membershipsTable)
    .where(and(eq(membershipsTable.id, membershipId), eq(membershipsTable.organizationId, organizationId)))
    .limit(1);
  return membership;
};

const membershipSchema = z
  .object({
    ...createSelectSchema(membershipsTable).shape,
    // Override enum columns with explicit schemas to preserve literal types
    role: entityRoleSchema,
    contextType: contextEntityTypeSchema,
  })
  .openapi('Membership', {
    description: "A user's membership in a context entity, including role and activity data.",
    example: mockMembershipResponse(),
    'x-tags': schemaTags('data', 'memberships', 'cella'),
  });

registerTag({
  tag: 'organizations',
  kind: 'module',
  parent: 'cella',
  description: `Endpoints for managing \`organizations\`, which are core context entities. Organizations are
    the highest ancestor in the parent hierarchy. They define access boundaries and are often the minimal
    primary scope for permission and resource management.`,
});

const findContextCounters = async (ctx: DbContext, { contextIds }: FindContextCountersOpts) => {
  const { db } = ctx.var;
  return db
    .select({
      contextKey: contextCountersTable.contextKey,
      counts: contextCountersTable.counts,
    })
    .from(contextCountersTable)
    .where(inArray(contextCountersTable.contextKey, contextIds));
};

registerTag({
  tag: 'users',
  kind: 'module',
  parent: 'cella',
  description: `Endpoints for managing *users* at the system level. Unlike context entities (such as
    \`organizations\`), a \`user\` is a "global" entity and not scoped to a specific context. These endpoints
    are intended for administrative operations on any user in the system.`,
});

return validator("query", async (value, c) => {
	let result: z.SafeParseReturnType<z.input<T>, z.output<T>>;
	try {
		const coerced = coerceValue(schema, value);
		result = await schema.safeParseAsync(coerced);
	} catch (error) {
		if (error instanceof z.ZodError) {
			return validationHook({ success: false, error }, c);
		}
		throw error;
	}
	if (!result.success) {
		return validationHook(result, c);
	}
	return result.data as z.output<T>;
});

class MockContext implements ExecutionContext {
  passThroughOnException(): void {
    throw new Error('Method not implemented.')
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  async waitUntil(promise: Promise<any>): Promise<void> {
    await promise
  }
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  props: any
}

crossSeed.post('/cache/:instanceId/clear', (c) => {
	const user = c.get('user')
	const instanceId = parseInt(c.req.param('instanceId'))
	if (!userOwnsInstance(user.id, instanceId)) {
		return c.json({ error: 'Instance not found' }, 404)
	}

	const cacheCleared = clearCacheForInstance(instanceId)
	const outputCleared = clearOutputForInstance(instanceId)

	return c.json({ cacheCleared, outputCleared })
})

try {
  await verifyGiteaToken(normalizedBase, resolvedToken);

  const client = createGiteaClient({
    baseUrl: normalizedBase,
    accessToken: resolvedToken,
  });
  await client.getRepo(repositoryOwner, repositoryName);
} catch (error) {
  if (error instanceof GiteaApiError) {
    throw new HTTPException(error.status || 400, { message: error.message });
  }
  throw error;
}

if (existingIntegration) {
  try {
    const previousConfig = JSON.parse(
      existingIntegration.config,
    ) as GiteaConfig;
    webhookSecret = previousConfig.webhookSecret ?? webhookSecret;
  } catch (error) {
    console.warn("Failed to parse existing Gitea config for webhook secret", {
      integrationId: existingIntegration.id,
      error,
    });
  }
}

if (!context) {
  console.info("Notification delivery skipped: unresolved context", {
    notificationId,
    notificationTableId: notification.id,
    resourceType: notification.resourceType,
    resourceId: notification.resourceId,
    reason:
      "resolveNotificationContext returned null (missing resource, deleted task, or unsupported resource type)",
  });
  return;
}

if (
  decryptedPreference.gotifyEnabled &&
  decryptedPreference.gotifyServerUrl &&
  decryptedPreference.gotifyToken &&
  rule.gotifyEnabled
) {
  deliveries.push(
    sendGotifyNotification({
      serverUrl: decryptedPreference.gotifyServerUrl,
      token: decryptedPreference.gotifyToken,
      title: content.title,
      body: content.body,
      clickUrl: context.taskUrl,
    }),
  );
}

type UpdateNotificationPreferenceInput = {
  emailEnabled?: boolean;
  ntfyEnabled?: boolean;
  ntfyServerUrl?: string | null;
  ntfyTopic?: string | null;
  ntfyToken?: string | null;
  gotifyEnabled?: boolean;
  gotifyServerUrl?: string | null;
  gotifyToken?: string | null;
  webhookEnabled?: boolean;
  webhookUrl?: string | null;
  webhookSecret?: string | null;
};
